// Build a Slack markdown digest from aggregated timing rows.
const rows = items.map(i => i.json);
if (rows.length === 0) {
  return [{ json: { formattedMessage: ':hourglass: *n8n weekly timing digest*\nNo Observer events in the last 7 days.' } }];
}

const lines = rows.map((r, i) => {
  const rank = String(i + 1).padStart(2, ' ');
  const ms = r.avg_ms.toString().padStart(6, ' ');
  return `${rank}.  \`${ms} ms\`  ${r.workflow_name} → *${r.node_name}*  (runs: ${r.runs}, max: ${r.max_ms} ms)`;
});

const header = ':hourglass_flowing_sand: *n8n weekly timing digest — top 10 slowest nodes (7-day avg)*';
const body = lines.join('\n');
return [{ json: { formattedMessage: `${header}\n${body}` } }];
